#!/usr/bin/env node

/**
 * Output Component Implementation Validator - Enhanced Version
 *
 * ============================================================================
 * IMPORTANT: ONLY FOR CLAUDE-GENERATED FILES
 * ============================================================================
 *
 * This validator should ONLY be run on files that were NEWLY GENERATED BY CLAUDE.
 *
 * Purpose:
 *   - Verify that Claude-generated output components follow all guidelines
 *   - Catch guideline violations before they enter the codebase
 *   - Ensure consistent patterns in AI-generated output field components
 *
 * When to use:
 *   - After Claude generates a new output field component
 *   - After Claude creates a custom output display component
 *   - After Claude modifies MvsFormFieldOutputBaseComponent extensions
 *
 * When NOT to use:
 *   - On existing legacy output components
 *   - On third-party or external code
 *   - On manually written code (unless verifying against guidelines)
 *
 * ============================================================================
 * AUTO-CORRECTION WORKFLOW
 * ============================================================================
 *
 * When this script reports errors on Claude-generated files:
 *
 * 1. CLAUDE MUST read the error messages carefully
 * 2. CLAUDE MUST fix each violation in the generated file
 * 3. CLAUDE MUST re-run this validation script
 * 4. REPEAT steps 1-3 until ALL checks pass (✅)
 *
 * Claude should NEVER leave a file with validation errors.
 * The auto-correction loop continues until zero errors remain.
 *
 * Example workflow:
 *   - Claude generates mvs-form-control-output-custom.component.ts
 *   - Run: node check-guidelines.js ./mvs-form-control-output-custom.component.ts
 *   - ERROR: "Missing refreshComponent() method"
 *   - Claude fixes: adds refreshComponent() implementation
 *   - Run: node check-guidelines.js ./mvs-form-control-output-custom.component.ts
 *   - ✅ Validation PASSED
 *
 * ============================================================================
 *
 * Comprehensive validation for output field component implementations.
 * Validates ALL requirements from SKILL.md documentation.
 *
 * Validates:
 * 1. Component Structure
 *    - @Component() decorator
 *    - Extends MvsFormFieldOutputBaseComponent
 *    - Correct selector pattern (mvs-form-control-output-* or mvs-form-control-*)
 *    - Implements OnInit, OnChanges, OnDestroy
 *
 * 2. Required Inputs
 *    - @Input() value (required)
 *    - @Input() formField (optional)
 *    - @Input() dto (optional)
 *    - @Input() form (optional)
 *
 * 3. Required Outputs
 *    - @Output() onFieldValueSelected (for interactive outputs)
 *
 * 4. Lifecycle Methods
 *    - ngOnInit() with super.ngOnInit()
 *    - ngOnChanges() implementation
 *    - ngOnDestroy() implementation
 *
 * 5. Required Methods
 *    - refreshComponent()
 *
 * 6. Required Patterns
 *    - this.initialized = true
 *    - Null/undefined value handling
 *    - Value formatting/display logic
 *
 * Usage: node check-guidelines.js <path-to-component.ts>
 *
 * Exit Codes:
 *   0 = All validations passed
 *   1 = One or more validations failed
 */

const fs = require('fs');
const path = require('path');

// ANSI color codes
const colors = {
  reset: '\x1b[0m',
  red: '\x1b[31m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  cyan: '\x1b[36m',
  magenta: '\x1b[35m',
  dim: '\x1b[2m'
};

function print(message, color = 'reset') {
  console.log(`${colors[color]}${message}${colors.reset}`);
}

function printSection(title) {
  console.log();
  print(`▸ ${title}`, 'magenta');
  print('─'.repeat(50), 'dim');
}

// Validation results tracker
const results = {
  passed: [],
  failed: [],
  warnings: [],
  skipped: []
};

function pass(rule, detail = '') {
  results.passed.push({ rule, detail });
  const detailStr = detail ? ` ${colors.dim}(${detail})${colors.reset}` : '';
  print(`  ✓ ${rule}${detailStr}`, 'green');
}

function fail(rule, hint = '') {
  results.failed.push({ rule, hint });
  print(`  ✗ ${rule}`, 'red');
  if (hint) {
    print(`    └─ Hint: ${hint}`, 'yellow');
  }
}

function warn(message, hint = '') {
  results.warnings.push({ message, hint });
  print(`  ⚠ ${message}`, 'yellow');
  if (hint) {
    print(`    └─ ${hint}`, 'dim');
  }
}

function skip(rule, reason = '') {
  results.skipped.push({ rule, reason });
  print(`  ○ ${rule} ${colors.dim}(skipped: ${reason})${colors.reset}`, 'dim');
}

/**
 * Main validation function
 */
function validateOutputComponent(filePath) {
  // Print header
  console.log();
  print('╔══════════════════════════════════════════════════════════════════════╗', 'cyan');
  print('║       Output Component Implementation Validator (Enhanced)           ║', 'cyan');
  print('║                    Coverage: 100% of SKILL.md                        ║', 'cyan');
  print('╚══════════════════════════════════════════════════════════════════════╝', 'cyan');

  // Check file exists
  if (!fs.existsSync(filePath)) {
    print(`\n✗ File not found: ${filePath}`, 'red');
    process.exit(1);
  }

  const content = fs.readFileSync(filePath, 'utf-8');
  const fileName = path.basename(filePath);

  print(`\nFile: ${fileName}`, 'blue');
  print(`Path: ${filePath}`, 'dim');

  // ═══════════════════════════════════════════════════════════════════════════
  // SECTION 1: Component Structure
  // ═══════════════════════════════════════════════════════════════════════════
  printSection('Component Structure');

  // 1.1 Check @Component() decorator
  const componentDecoratorPattern = /@Component\s*\(\s*\{/;
  if (componentDecoratorPattern.test(content)) {
    pass('@Component() decorator present');
  } else {
    fail(
      'Missing @Component() decorator',
      'Add @Component({ selector: "...", template: "..." }) above the class'
    );
  }

  // 1.2 Check extends MvsFormFieldOutputBaseComponent
  const extendsPattern = /extends\s+MvsFormFieldOutputBaseComponent/;
  if (extendsPattern.test(content)) {
    pass('Extends MvsFormFieldOutputBaseComponent');
  } else {
    fail(
      'Component must extend MvsFormFieldOutputBaseComponent',
      'Change to: export class YourComponent extends MvsFormFieldOutputBaseComponent'
    );
  }

  // 1.3 Check selector pattern
  const selectorPattern = /selector:\s*['"]([^'"]+)['"]/;
  const selectorMatch = content.match(selectorPattern);
  if (selectorMatch) {
    const selector = selectorMatch[1];
    if (selector.startsWith('mvs-form-control-output-') || selector.startsWith('mvs-form-control-')) {
      pass(`Selector matches pattern`, selector);
    } else {
      fail(
        `Selector should start with 'mvs-form-control-output-' or 'mvs-form-control-'`,
        `Found: '${selector}'. Change to: 'mvs-form-control-output-[your-component-name]'`
      );
    }
  } else {
    fail('No selector found in @Component decorator');
  }

  // 1.4 Check implements interfaces
  const implementsPattern = /implements\s+([^{]+)/;
  const implementsMatch = content.match(implementsPattern);
  if (implementsMatch) {
    const interfaces = implementsMatch[1];
    const hasOnInit = /OnInit/.test(interfaces);
    const hasOnChanges = /OnChanges/.test(interfaces);
    const hasOnDestroy = /OnDestroy/.test(interfaces);

    const implemented = [];
    if (hasOnInit) implemented.push('OnInit');
    if (hasOnChanges) implemented.push('OnChanges');
    if (hasOnDestroy) implemented.push('OnDestroy');

    if (implemented.length === 3) {
      pass('Implements OnInit, OnChanges, OnDestroy');
    } else if (implemented.length > 0) {
      pass(`Implements ${implemented.join(', ')}`);
      const missing = [];
      if (!hasOnInit) missing.push('OnInit');
      if (!hasOnChanges) missing.push('OnChanges');
      if (!hasOnDestroy) missing.push('OnDestroy');
      if (missing.length > 0) {
        warn(`Missing interfaces: ${missing.join(', ')}`);
      }
    } else {
      warn('No lifecycle interfaces implemented');
    }
  } else {
    warn(
      'No implements clause found',
      'Consider adding: implements OnInit, OnChanges'
    );
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // SECTION 2: Input Properties
  // ═══════════════════════════════════════════════════════════════════════════
  printSection('Input Properties');

  // 2.1 Check @Input() value - inherited from base but check usage
  const valueInputPattern = /@Input\(\)\s*value/;
  const valueUsagePattern = /this\.value/;
  if (valueInputPattern.test(content)) {
    pass('@Input() value declared');
  } else if (valueUsagePattern.test(content)) {
    pass('Uses this.value (inherited from base)');
  } else if (extendsPattern.test(content)) {
    pass('Inherits @Input() value from base');
  } else {
    fail(
      'Missing @Input() value property',
      'Add @Input() value: any; or inherit from MvsFormFieldOutputBaseComponent'
    );
  }

  // 2.2 Check @Input() formField usage
  const formFieldPattern = /@Input\(\)\s*formField|this\.formField/;
  if (formFieldPattern.test(content)) {
    pass('Uses formField (for configuration)');
  } else {
    skip('@Input() formField', 'optional - inherited from base');
  }

  // 2.3 Check @Input() dto usage
  const dtoPattern = /@Input\(\)\s*dto|this\.dto/;
  if (dtoPattern.test(content)) {
    pass('Uses dto (for context)');
  } else {
    skip('@Input() dto', 'optional - for additional context');
  }

  // 2.4 Check @Input() form usage
  const formPattern = /@Input\(\)\s*form|this\.form/;
  if (formPattern.test(content)) {
    pass('Uses form (for form definition)');
  } else {
    skip('@Input() form', 'optional - for form context');
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // SECTION 3: Output Properties
  // ═══════════════════════════════════════════════════════════════════════════
  printSection('Output Properties');

  // 3.1 Check @Output() onFieldValueSelected
  const outputPattern = /@Output\(\)\s*onFieldValueSelected/;
  const emitPattern = /this\.onFieldValueSelected\.emit/;
  if (outputPattern.test(content)) {
    pass('@Output() onFieldValueSelected declared');
    if (emitPattern.test(content)) {
      pass('Emits onFieldValueSelected event');
    } else {
      warn(
        'onFieldValueSelected declared but never emitted',
        'Consider emitting on user interaction'
      );
    }
  } else if (emitPattern.test(content)) {
    pass('Emits onFieldValueSelected (inherited from base)');
  } else {
    skip('@Output() onFieldValueSelected', 'optional - for interactive outputs');
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // SECTION 4: Lifecycle Methods
  // ═══════════════════════════════════════════════════════════════════════════
  printSection('Lifecycle Methods');

  // 4.1 Check ngOnInit with super call
  const ngOnInitPattern = /ngOnInit\s*\(\s*\)\s*[:{]/;
  const superNgOnInitPattern = /super\.ngOnInit\s*\(\s*\)/;
  if (ngOnInitPattern.test(content)) {
    if (superNgOnInitPattern.test(content)) {
      pass('ngOnInit() calls super.ngOnInit()');
    } else {
      fail(
        'Missing super.ngOnInit() in ngOnInit()',
        'Add super.ngOnInit() as the FIRST line in ngOnInit()'
      );
    }

    // Check if refreshComponent is called in ngOnInit
    const refreshInOnInitPattern = /ngOnInit[\s\S]*?this\.refreshComponent\s*\(\s*\)/;
    if (refreshInOnInitPattern.test(content)) {
      pass('refreshComponent() called in ngOnInit()');
    } else {
      warn('refreshComponent() not called in ngOnInit()');
    }
  } else {
    skip('ngOnInit() method', 'base class handles initialization');
  }

  // 4.2 Check ngOnChanges
  const ngOnChangesPattern = /ngOnChanges\s*\([^)]*\)\s*[:{]/;
  if (ngOnChangesPattern.test(content)) {
    pass('Implements ngOnChanges()');

    // Check if it handles value changes
    const valueChangePattern = /ngOnChanges[\s\S]*?(changes\[['"]value['"]\]|this\.refreshComponent)/;
    if (valueChangePattern.test(content)) {
      pass('ngOnChanges handles value updates');
    } else {
      warn(
        'ngOnChanges may not handle value updates',
        'Add: if (changes["value"]) { this.refreshComponent(); }'
      );
    }

    // Check for initialized guard
    const initGuardPattern = /ngOnChanges[\s\S]*?(!this\.initialized|!initialized)/;
    if (initGuardPattern.test(content)) {
      pass('ngOnChanges has initialized guard');
    } else {
      warn(
        'Consider adding initialized guard in ngOnChanges',
        'Add: if (!this.initialized) return;'
      );
    }
  } else {
    warn(
      'No ngOnChanges() implementation',
      'Consider implementing to handle value updates'
    );
  }

  // 4.3 Check ngOnDestroy
  const ngOnDestroyPattern = /ngOnDestroy\s*\(\s*\)\s*[:{]/;
  const superNgOnDestroyPattern = /super\.ngOnDestroy\s*\(\s*\)/;
  if (ngOnDestroyPattern.test(content)) {
    if (superNgOnDestroyPattern.test(content)) {
      pass('ngOnDestroy() calls super.ngOnDestroy()');
    } else {
      warn('Missing super.ngOnDestroy() call');
    }
  } else {
    skip('ngOnDestroy() method', 'base class handles cleanup');
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // SECTION 5: Required Methods
  // ═══════════════════════════════════════════════════════════════════════════
  printSection('Required Methods');

  // 5.1 Check refreshComponent() method
  const refreshComponentPattern = /refreshComponent\s*\(\s*\)\s*[:{]/;
  if (refreshComponentPattern.test(content)) {
    pass('Implements refreshComponent() method');

    // Check if it processes value
    const processValuePattern = /refreshComponent[\s\S]*?this\.value/;
    if (processValuePattern.test(content)) {
      pass('refreshComponent() processes this.value');
    } else {
      warn('refreshComponent() should process this.value');
    }
  } else {
    fail(
      'Missing refreshComponent() method',
      'Add: refreshComponent() { /* format and display this.value */ }'
    );
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // SECTION 6: Required Patterns
  // ═══════════════════════════════════════════════════════════════════════════
  printSection('Required Patterns');

  // 6.1 Check initialized = true
  const initializedPattern = /this\.initialized\s*=\s*true/;
  if (initializedPattern.test(content)) {
    pass('Sets this.initialized = true');
  } else {
    fail(
      'Missing "this.initialized = true"',
      'Add this.initialized = true at the end of ngOnInit() or refreshComponent()'
    );
  }

  // 6.2 Check null/undefined handling
  const nullCheckPatterns = [
    /!this\.value/,
    /this\.value\s*===\s*null/,
    /this\.value\s*===\s*undefined/,
    /this\.value\s*==\s*null/,
    /this\.value\s*\?\?/,
    /this\.value\s*\|\|/,
    /if\s*\(\s*!this\.value/,
    /this\.value\s*===\s*['"]-['"]/,
    /this\.value\s*==\s*['"]-['"]/,
    /\?\./  // Optional chaining
  ];

  const hasNullCheck = nullCheckPatterns.some(pattern => pattern.test(content));
  if (hasNullCheck) {
    pass('Handles null/undefined values');
  } else {
    warn(
      'No explicit null/undefined check for this.value',
      'Add: if (!this.value || this.value === "-") { return; }'
    );
  }

  // 6.3 Check for formatted/display value
  const displayValuePatterns = [
    /formattedValue/i,
    /displayValue/i,
    /displayText/i,
    /formatted\w+/,
    /display\w+/
  ];

  const hasDisplayValue = displayValuePatterns.some(pattern => pattern.test(content));
  if (hasDisplayValue) {
    pass('Has formatted/display value property');
  } else {
    warn(
      'No formatted/display value property found',
      'Consider using a property like formattedValue for display'
    );
  }

  // 6.4 Check for value transformation/formatting
  const formattingPatterns = [
    /toLocaleDateString|toLocaleTimeString|toLocaleString/,
    /DatePipe|DecimalPipe|CurrencyPipe/,
    /format\w*\(/i,
    /transform\w*\(/i,
    /\.toFixed\(/,
    /\.toString\(/,
    /\.substring\(|\.slice\(/,
    /\.toUpperCase\(|\.toLowerCase\(/
  ];

  const hasFormatting = formattingPatterns.some(pattern => pattern.test(content));
  if (hasFormatting) {
    pass('Has value formatting/transformation');
  } else {
    skip('Value formatting', 'may display raw value');
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // SECTION 7: Template Checks (if inline template)
  // ═══════════════════════════════════════════════════════════════════════════
  const inlineTemplatePattern = /template\s*:\s*[`'"]([^`'"]*)[`'"]/s;
  const inlineTemplateMatch = content.match(inlineTemplatePattern);

  if (inlineTemplateMatch) {
    printSection('Template Validation');
    const template = inlineTemplateMatch[1];

    // Check for conditional display
    if (/\*ngIf|\[ngIf\]|@if/.test(template)) {
      pass('Template has conditional display');
    } else {
      warn('Template has no conditional display (*ngIf)');
    }

    // Check for data binding
    if (/\{\{.*\}\}|\[.*\]=/.test(template)) {
      pass('Template has data binding');
    } else {
      warn('Template has no visible data binding');
    }
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // Print Summary
  // ═══════════════════════════════════════════════════════════════════════════
  console.log();
  print('═'.repeat(70), 'cyan');
  print('  VALIDATION SUMMARY', 'cyan');
  print('═'.repeat(70), 'cyan');
  console.log();

  const total = results.passed.length + results.failed.length;
  const passRate = total > 0 ? Math.round((results.passed.length / total) * 100) : 0;

  print(`  ✓ Passed:   ${results.passed.length}`, 'green');
  print(`  ✗ Failed:   ${results.failed.length}`, results.failed.length > 0 ? 'red' : 'green');
  print(`  ⚠ Warnings: ${results.warnings.length}`, results.warnings.length > 0 ? 'yellow' : 'green');
  print(`  ○ Skipped:  ${results.skipped.length}`, 'dim');
  console.log();
  print(`  Pass Rate:  ${passRate}%`, passRate === 100 ? 'green' : passRate >= 70 ? 'yellow' : 'red');

  console.log();
  print('═'.repeat(70), 'cyan');

  // Exit with appropriate code
  if (results.failed.length > 0) {
    console.log();
    print('❌ Validation FAILED - Please fix the errors above', 'red');
    console.log();
    process.exit(1);
  } else if (results.warnings.length > 0) {
    console.log();
    print('⚠️  Validation PASSED with warnings', 'yellow');
    console.log();
    process.exit(0);
  } else {
    console.log();
    print('✅ Validation PASSED - Component follows all guidelines!', 'green');
    console.log();
    process.exit(0);
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// CLI Entry Point
// ═══════════════════════════════════════════════════════════════════════════

const filePath = process.argv[2];

if (!filePath) {
  console.log();
  print('Output Component Implementation Validator', 'cyan');
  print('─'.repeat(40), 'dim');
  console.log();
  print('Usage:', 'yellow');
  print('  node check-guidelines.js <path-to-component.ts>', 'reset');
  console.log();
  print('Example:', 'yellow');
  print('  node check-guidelines.js ./my-output.component.ts', 'reset');
  print('  node check-guidelines.js src/app/shared/form/output/date/date.component.ts', 'reset');
  console.log();
  print('Validates:', 'blue');
  print('  • Component structure (extends, selector, decorator)', 'reset');
  print('  • Input properties (value, formField, dto)', 'reset');
  print('  • Output properties (onFieldValueSelected)', 'reset');
  print('  • Lifecycle methods (ngOnInit, ngOnChanges, ngOnDestroy)', 'reset');
  print('  • Required methods (refreshComponent)', 'reset');
  print('  • Required patterns (initialized, null handling)', 'reset');
  console.log();
  process.exit(1);
}

// Resolve to absolute path and run validation
const absolutePath = path.resolve(filePath);
validateOutputComponent(absolutePath);
